const MUST = [
  '(AI OR "large language model" OR LLM OR 生成式)'
];
const MUST_NOT = [

];

const CFG = {
  QUERY: `${MUST.join(' AND ')} ${MUST_NOT.map(x => `-${x}`).join(' ')}`,
  LANGUAGE: 'en',
  FROM_DAYS: 7,
  MAX_ARTICLES: 50,
  TAKE_TOP: 30,
  OPENAI_CHAT: 'gpt-4o',
  OPENAI_IMAGE: 'gpt-image-1',
  COVER_SIZE: '1024x576',
  BODY_SIZE: '1024x1024',
  BRAND: {
    palette: ['#0F172A','#22D3EE','#A78BFA'],
    style: 'editorial illustration, semi-flat, clean, minimal, soft lighting',
    negatives: 'text, watermark, logo, brand, people, realistic faces, hands, busy background'
  },
  // 建议改为：四大分析/洞察优先
  PREFERRED_CATEGORIES : ['tech_insight','industry_insight','deep_tech','product_insight'],

  WEIGHTS : {
    // ——基础权重（总分贡献占比）——
    base: { sourceTrust: 0.25, recency: 0.15, length: 0.15 },

    // ——正向信号（每命中一次的基点，内部会封顶/衰减）——
    signals: {
      // 洞察/分析
      insight: {
        titleCue: 12,      // 标题/URL含 how/why/analysis/解读/洞察/详解/拆解
        keyword: 10,       // 文内 analysis/deep dive/inside/趋势/产业链 等
        industry: 10,      // 芯片/供应链/封装/HBM/产能/节点nm 等行业词
        longform: 8,       // 文本较长（>1500字节）额外加
        trustedHost: 6     // 可信媒体（BBC/FT/Reuters/WSJ/Ars/Wired…）
      },
      // 技术进展
      tech: {
        terms: 6,          // architecture/ablation/SOTA/quantization/MoE 等
        paper: 9,          // arXiv/OpenReview 链接或提及
        code: 7,           // GitHub/HF 仓库
        benchmark: 7,      // MMLU/GSM8K/ImageNet/COCO/GLUE…
        numbers: 2         // 有指标/百分比/大数（轻微加）
      }
    },

    // ——负向信号（每命中一次的扣分；strong insight/tech 时会折扣）——
    penalties: {
      pr: 9,               // PR/活动/发布会/获奖/合作/招聘/调查
      policy: 7,           // 纯政策/法案/合规（分析类会折扣）
      productNews: 4       // 纯产品发布口径（无技术/无拆解）
    },
    dampIfStrong: {        // 有料则“罚款打折”
      threshold: 18,       // insightBoost+techBoost ≥ 18
      factor: 0.5
    },

    // ——类别乘数（最后乘以这个系数，决定“谁更上头条”）——
    categoryMultiplier: {
      tech_insight:     1.25,  // 技术分析/技术洞察 —— 最高
      industry_insight: 1.25,  // 行业分析/行业洞察 —— 最高
      deep_tech:        1.12,  // 论文/基准/代码等“硬技术进展”
      product_insight:  1.08,  // 产品架构拆解/对比评测
      product_news:     0.85,  // 纯上新/公告
      policy_news:      0.80,  // 纯政策新闻
      pr_event:         0.60,  // PR/活动/获奖/招聘等
      other:            0.75
    },

    // ——时效曲线（洞察类不用太追 24h 热点）——
    recencyHalfLifeHours: 96   // 半衰期 96h：4 天内仍有权重
  }
};

CFG.FROM_ISO = new Date(Date.now() - CFG.FROM_DAYS*24*60*60*1000).toISOString();
return [{json: CFG}];

/***********************
 * ScoreSelect (All-in-one)
 * - Flattens inputs (articles[] or multi-items)
 * - Normalizes & hashes (FNV-1a)
 * - Historical dedup (seen.json)
 * - Batch dedup (Jaro-Winkler)
 * - Category detect + scoring
 * - Emits { primary, related, candidates, seenState, debug }
 * Mode: Run once for all items
 ***********************/

/* ========= Utilities ========= */
function fnv1aHex(str=''){ let h=0x811c9dc5; for(let i=0;i<str.length;i++){ h^=str.charCodeAt(i); h+=(h<<1)+(h<<4)+(h<<7)+(h<<8)+(h<<24);} return (h>>>0).toString(16).padStart(8,'0');}
function toHalfWidth(s=''){ return s.replace(/[\u2018\u2019]/g,"'").replace(/[\u201C\u201D]/g,'"').replace(/[\uFF01-\uFF5E]/g,ch=>String.fromCharCode(ch.charCodeAt(0)-0xFEE0)).replace(/\u3000/g,' '); }
function normalizeUrl(u){ try{ const url=new URL(u); url.hash=''; const drop=['utm_source','utm_medium','utm_campaign','utm_term','utm_content','ref','fbclid','gclid','yclid','spm','igshid','mc_cid','mc_eid','share_type','share_pt']; for (const k of drop) url.searchParams.delete(k); const host=url.hostname.replace(/^www\./,'').toLowerCase(); const path=url.pathname.replace(/\/+$/,''); const qs=[...url.searchParams.entries()].sort((a,b)=>a[0].localeCompare(b[0])); return `${host}${path}${qs.length?('?'+qs.map(x=>`${x[0]}=${x[1]}`).join('&')):''}`; }catch{ return (u||'').replace(/^https?:\/\//,'').replace(/^www\./,'');}}
function normalizeTitle(t='', url=''){ let s=toHalfWidth(t).trim(); const host=(()=>{try{return new URL(url).hostname.replace(/^www\./,'');}catch{return '';} })(); if (host) s=s.replace(new RegExp(`\\s*[-|—|\\|]\\s*${host.replace(/\./g,'\\.')}$`,'i'),''); s=s.replace(/[（(](评论|社评|快讯|图解|直播)[)）]$/,''); s=s.replace(/[“”"‘’'、，,。.！!？?\[\]【】<>（）()：:;；]/g,' ').replace(/\s+/g,' ').trim(); return s;}
function jaroWinkler(a='', b=''){ a=a.toLowerCase(); b=b.toLowerCase(); const mt=(s,t)=>{ const m=Math.max(s.length,t.length)/2-1|0; const ms1=new Array(s.length).fill(false), ms2=new Array(t.length).fill(false); let matches=0, trans=0; for(let i=0;i<s.length;i++){ const st=Math.max(0,i-m), en=Math.min(i+m+1,t.length); for(let j=st;j<en;j++){ if(ms2[j]) continue; if(s[i]===t[j]){ ms1[i]=ms2[j]=true; matches++; break; } } } if(!matches) return [0,0]; let k=0; for(let i=0;i<s.length;i++) if(ms1[i]){ while(!ms2[k]) k++; if(s[i]!==t[k]) trans++; k++; } return [matches, trans/2]; }; const [m,t]=mt(a,b); if(!m) return 0; const j=(m/a.length + m/b.length + (m-t)/m)/3; let l=0; while(l<4 && a[l] && b[l] && a[l]===b[l]) l++; return j + l*0.1*(1-j); }
function safeItems(name){ try{ const out=$items(name,0,0,{returnAll:true}); return Array.isArray(out)?out:[]; } catch { return []; } }
/* function parseSeen(fromGithub){
  const obj = fromGithub?.[0]?.json || {};
  let entries=[], sha=null;
  try{
    if (obj.content) {
      const txt = Buffer.from(obj.content,'base64').toString('utf8');
      entries = JSON.parse(txt || '[]');
      sha = obj.body?.sha || null;
    }
  }catch(e){ entries=[]; sha=null; }
  return { entries: Array.isArray(entries)?entries:[], sha };
} */
function parseSeen(fromGithub){
  const obj  = fromGithub?.[0]?.json || {};
  const body = (obj && typeof obj.body === 'object') ? obj.body : obj; // 关键：兼容 fullResponse
  let entries = [], sha = null;
  try {
    const b64 = body?.content || '';
    if (b64) {
      const txt = Buffer.from(b64, 'base64').toString('utf8');
      entries = JSON.parse(txt || '[]');
    }
    sha = body?.sha || null;
  } catch { /* noop */ }
  return { entries: Array.isArray(entries) ? entries : [], sha };
}

/* ========= Config ========= */
const cfg = (safeItems('SetConfig')[0]?.json) || {};
const TAKE_TOP_N   = Number(cfg.TOP_N || 4);            // 1 + (N-1)
const TTL_DAYS     = Number(cfg.SEEN_TTL_DAYS || 35);
const PREF_CATS    = cfg.PREFERRED_CATEGORIES || ['deep_tech','industry_insight','tech_insight','product_insight'];
const EMIT_MULT    = Boolean(cfg.EMIT_MULTIPLE);         // 可选：多条 item 输出模式（默认 false 聚合输出）

/* ========= Flatten input ========= */
// 支持：① 1 条 item 里有 articles[] 或 data.articles[]；② 多条 item 各一篇
let news = $('NewsFetch').first().json.articles;
/*
const raw = (items || []).map(it => it.json || {});
if (raw.length === 1 && Array.isArray(raw[0]?.articles)) {
  news = raw[0].articles;
} else if (raw.length === 1 && Array.isArray(raw[0]?.data?.articles)) {
  news = raw[0].data.articles;
} else {
  news = raw;
}
*/

// 宽松映射别名
const pickUrl   = (a={}) => a.url || a.link || a.permalink || a.guid || a.sourceUrl || a.storyUrl || '';
const pickTitle = (a={}) => a.title || a.headline || a.name || a.subject || '';

const droppedBasic = [];
news = news.map(a => ({ ...a, url: pickUrl(a), title: pickTitle(a) }))
           .filter(a => {
             const ok = Boolean(a.url && a.title);
             if (!ok) droppedBasic.push({ sample: { url: a.url, title: a.title }, reason: 'missing url/title' });
             return ok;
           });
const TOTAL_IN = news.length;

/* ========= Load seen.json ========= */
const seen = parseSeen(safeItems('GetSeen'));
const seenUrl = new Set();
const seenTitle = new Set();
const seenTitleNorms = [];
const now = Date.now();
const TTL_MS = TTL_DAYS * 24 * 3600 * 1000;

for (const r of seen.entries) {
  const ts = new Date(r.firstSeenAt || 0).getTime();
  if (!ts || (now - ts) > TTL_MS) continue;  // 滚动窗口
  if (r.urlKey)   seenUrl.add(r.urlKey);
  if (r.titleKey) seenTitle.add(r.titleKey);
  if (r.titleNorm) seenTitleNorms.push(String(r.titleNorm).toLowerCase());
}

/* ========= Category & Scoring ========= */
function detectCategory(rec){
  const t = `${rec.title||''} ${rec.description||''}`.toLowerCase();
  const u = (rec.url||'').toLowerCase();
  const deep = /(paper|arxiv|openreview|architecture|benchmark|inference|latency|throughput|kernel|compiler|quantization|lora|moe|attention|nvlink|hbm|npu|asic|fpga|dataset|pretrain|fine[-\s]?tune|weights|distillation|opensource|open[-\s]?source)/;
  const ind  = /(market|landscape|trend|survey|outlook|valuation|supply\s?chain|capacity|foundry|capex|pricing|shipment|import|export|ban|sanction|nvidia|nvda|amd|intel|tsmc|smic|samsung|huawei)/;
  const tech = /(postmortem|post[-\s]?mortem|root\s?cause|retrospective|scaling|optimization|observability|incident|outage|design\s?notes|engineering)/;
  const prod = /(roadmap|case\s?study|changelog|release\s?notes|product\s?update|design\s?decision)/;
  const pr   = /(announces?|launch(es)?|partnership|program|initiative|grant|award|event|conference|webinar|summit|hiring)/;
  const policy=/(regulation|policy|bill|law|ban|compliance|guideline|white\s?paper)/;

  if (deep.test(t) || /arxiv\.org|openreview\.net/.test(u)) return 'deep_tech';
  if (ind.test(t)) return 'industry_insight';
  if (tech.test(t)) return 'tech_insight';
  if (prod.test(t)) return 'product_insight';
  if (pr.test(t)) return 'news_pr';
  if (policy.test(t)) return 'policy';
  return 'other';
}
function catWeight(cat){
  const order = {
    deep_tech: 1.00,
    industry_insight: 0.95,
    tech_insight: 0.92,
    product_insight: 0.88,
    policy: 0.55,
    news_pr: 0.35,
    other: 0.40,
  };
  const base = order[cat] ?? 0.40;
  return base * (PREF_CATS.includes(cat) ? 1.10 : 1.0);
}
function recencyBonus(publishedAt){
  if (!publishedAt) return 0;
  const d = Math.max(0, (Date.now()-new Date(publishedAt).getTime())/(24*3600*1000));
  if (d <= 1) return 12;
  if (d <= 3) return 8;
  if (d <= 7) return 5;
  if (d <= 14) return 2;
  return 0;
}
function penaltyPR(rec){
  const t = `${rec.title||''} ${rec.description||''}`.toLowerCase();
  return /(announces?|launch|partnership|webinar|summit|award|program)/.test(t) ? -18 : 0;
}
function qualityScore(rec){
  const cat = detectCategory(rec);
  const base = 100 * catWeight(cat);
  const r    = recencyBonus(rec.publishedAt);
  const pr   = penaltyPR(rec);
  const len  = ((rec.content||'').length + (rec.description||'').length) > 320 ? 3 : 0;
  return Math.round(base + r + pr + len);
}

/* ========= Enrich + historical dedup ========= */
const enriched = [];
const droppedHist = [];

for (const a of news) {
  const _normUrl   = normalizeUrl(a.url);
  const _urlKey    = fnv1aHex(_normUrl);
  const _titleNorm = normalizeTitle(a.title, a.url);
  const _titleKey  = fnv1aHex(_titleNorm.toLowerCase());
  const category   = detectCategory(a);
  const QualityScore = qualityScore({ ...a, category });

  const histDup =
    seenUrl.has(_urlKey) ||
    seenTitle.has(_titleKey) ||
    (_titleNorm && seenTitleNorms.some(t => jaroWinkler(_titleNorm.toLowerCase(), t) >= 0.92));

  if (histDup) {
    droppedHist.push({ url: a.url, title: a.title, reason: 'seen' });
    continue;
  }

  enriched.push({
    source: a.source?.name || a.source || '',
    author: a.author || '',
    title: a.title || '',
    description: a.description || '',
    url: a.url,
    urlToImage: a.urlToImage || '',
    publishedAt: a.publishedAt || a.pubDate || '',
    content: a.content || '',
    category,
    QualityScore,
    _normUrl, _urlKey, _titleNorm, _titleKey, _hashAlgo: 'fnv1a32'
  });
}

/* ========= Batch dedup (similar titles) + sort ========= */
enriched.sort((a,b)=> (b.QualityScore||0) - (a.QualityScore||0));
/*
const kept = [];
const seenBatch = [];
const droppedBatch = [];

for (const c of enriched) {
  const t = (c._titleNorm||'').toLowerCase();
  const dup = seenBatch.some(x => jaroWinkler(t, x) >= 0.92) || seenBatch.includes(c._titleKey);
  if (dup) { droppedBatch.push({ url: c.url, title: c.title, reason: 'batch-dup' }); continue; }
  kept.push(c);
  seenBatch.push(c._titleKey || t);
}
*/

const kept = [];
const droppedBatch = [];
const seenBatchTitleKeys  = new Set();
const seenBatchUrlKeys    = new Set();
const seenBatchTitleNorms = []; // 用于相似度

for (const c of enriched) {
  const tNorm = (c._titleNorm || '').toLowerCase();
  const titleDup = seenBatchTitleKeys.has(c._titleKey) ||
                   seenBatchTitleNorms.some(x => jaroWinkler(tNorm, x) >= 0.92);
  const urlDup   = seenBatchUrlKeys.has(c._urlKey);

  if (titleDup || urlDup) {
    droppedBatch.push({ url: c.url, title: c.title, reason: urlDup ? 'dup-url' : 'dup-title' });
    continue;
  }

  kept.push(c);
  seenBatchTitleKeys.add(c._titleKey);
  seenBatchUrlKeys.add(c._urlKey);
  seenBatchTitleNorms.push(tNorm);
}

/* ========= Pick primary / related (with fallback) ========= */
let primary = kept[0] || null;
let related = kept.slice(1, TAKE_TOP_N);

if (!primary && enriched.length) {
  // 极端兜底：若批次去重过严导致空，至少给一篇
  primary = enriched[0];
  related = enriched.slice(1, TAKE_TOP_N);
}

/* ========= Emit ========= */
if (EMIT_MULT) {
  // 多条输出模式：每条一个候选
  return kept.map(k => ({ json: k }));
} else {
  // 单条聚合输出（推荐）
  return [{
    json: {
      primary,
      related,
      candidates: kept,
      seenState: { entries: seen.entries, sha: seen.sha, ttlDays: TTL_DAYS },
      debug: {
        droppedBasic,  // 缺 url/title
        droppedHist,   // 历史去重
        droppedBatch,  // 批次相似去重
        totalIn: TOTAL_IN,
        totalOut: kept.length
      }
    }
  }];
}

