/**
 * PickWinnerAndPrepareSeen
 * 依赖：ScoreSelect（已输出 primary / related[] / seenState，并且 meta 内已带 _urlKey/_titleKey/_titleNorm）
 * 分支：ReadPrimary / readRelated / readRelated2 / readRelated3（可能有的未执行）
 * 作用：按优先级挑出第一篇抓取成功的正文；生成 seen.json 的 GitHub PUT body
 */

// ---------- 工具 ----------
function safeItems(name) {
  try {
    const out = $items(name, 0, 0, { returnAll: true });
    return Array.isArray(out) ? out : [];
  } catch (_) { return []; }
}
function pickPayload(arr) {
  if (!Array.isArray(arr) || !arr.length) return null;
  const j = arr[0]?.json || {};
  // 你的抓取节点如果字段名不同（如 content/markdown），按需调整
  return j.data || j.markdown || j.content || null;
}

// 仅作兜底：如上游没带 key，才会用到这些函数（正常不会触发）
function fnv1aHex(str='') {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) { h ^= str.charCodeAt(i); h += (h<<1)+(h<<4)+(h<<7)+(h<<8)+(h<<24); }
  return (h>>>0).toString(16).padStart(8,'0');
}
function normalizeUrl(u) {
  try {
    const url = new URL(u); url.hash = '';
    const drop = ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','ref','fbclid','gclid','yclid','spm','igshid','mc_cid','mc_eid','share_type','share_pt'];
    for (const k of drop) url.searchParams.delete(k);
    const host = url.hostname.replace(/^www\./,'').toLowerCase();
    const path = url.pathname.replace(/\/+$/,'');
    const qs   = [...url.searchParams.entries()].sort((a,b)=>a[0].localeCompare(b[0]));
    return `${host}${path}${qs.length?('?'+qs.map(x=>`${x[0]}=${x[1]}`).join('&')):''}`;
  } catch { return (u||'').replace(/^https?:\/\//,'').replace(/^www\./,''); }
}
function toHalfWidth(s='') {
  return s.replace(/[\u2018\u2019]/g,"'")
          .replace(/[\u201C\u201D]/g,'"')
          .replace(/[\uFF01-\uFF5E]/g, ch => String.fromCharCode(ch.charCodeAt(0)-0xFEE0))
          .replace(/\u3000/g,' ');
}
function normalizeTitle(t='', url='') {
  let s = toHalfWidth(t).trim();
  const host = (()=>{ try{ return new URL(url).hostname.replace(/^www\./,''); }catch{return '';} })();
  if (host) s = s.replace(new RegExp(`\\s*[-|—|\\|]\\s*${host.replace(/\./g,'\\.')}$`,'i'), '');
  s = s.replace(/[（(](评论|社评|快讯|图解|直播)[)）]$/,'');
  s = s.replace(/[“”"‘’'、，,。.！!？?\[\]【】<>（）()：:;；]/g,' ')
       .replace(/\s+/g,' ')
       .trim();
  return s;
}

// ---------- 读取 ScoreSelect 输出 ----------
const ssItem = safeItems('ScoreSelect')[0]?.json || {};
const primaryMeta = ssItem.primary || null;
const relatedArr  = Array.isArray(ssItem.related) ? ssItem.related : [];
const seenStateIn = ssItem.seenState || { entries: [], sha: null, ttlDays: 35 };

// ---------- 读取抓取分支的实际正文 ----------
const branches = [
  { name: 'ReadPrimary',  meta: primaryMeta,        idx: 0, role: 'primary'     },
  { name: 'readRelated',  meta: relatedArr[0]||null,idx: 1, role: 'related_0'   },
  { name: 'readRelated2', meta: relatedArr[1]||null,idx: 2, role: 'related_1'   },
  { name: 'readRelated3', meta: relatedArr[2]||null,idx: 3, role: 'related_2'   },
];

let pickedMeta=null, pickedBody=null, pickedIdx=-1, pickedRole='';
const branchDebug = [];
for (const b of branches) {
  const arr  = safeItems(b.name);
  const body = pickPayload(arr);
  branchDebug.push({ branch: b.name, hasBody: !!body });
  if (body && b.meta && b.meta.url) {
    pickedMeta = b.meta;
    pickedBody = body;
    pickedIdx  = b.idx;
    pickedRole = b.role;
    break;
  }
}
if (!pickedBody) {
  throw new Error(JSON.stringify({ msg: 'No article content fetched from any branch.', branchDebug }));
}
if (!pickedMeta || !pickedMeta.url) {
  throw new Error(JSON.stringify({ msg: 'Picked article meta unavailable (check ScoreSelect output vs fetch branches).', pickedIdx, branchDebug }));
}

// ---------- 组装 selected（优先使用 ScoreSelect 已算好的 key） ----------
const urlKey   = pickedMeta._urlKey   || fnv1aHex(normalizeUrl(pickedMeta.url || ''));
const titleKey = pickedMeta._titleKey || fnv1aHex(normalizeTitle(pickedMeta.title || '', pickedMeta.url || '').toLowerCase());
const titleNorm= pickedMeta._titleNorm|| normalizeTitle(pickedMeta.title || '', pickedMeta.url || '');
const normUrl  = pickedMeta._normUrl  || normalizeUrl(pickedMeta.url || '');

const selected = {
  ...pickedMeta,
  selectedIndex: pickedIdx,
  selectedRole: pickedRole,
  body: pickedBody,
  _urlKey: urlKey,
  _titleKey: titleKey,
  _titleNorm: titleNorm,
  _normUrl: normUrl,
  _hashAlgo: pickedMeta._hashAlgo || 'fnv1a32'
};

// ---------- 合并 seen.entries 并生成 GitHub PUT body（幂等） ----------
const nowISO   = new Date().toISOString();
const ttlDays  = Number(seenStateIn.ttlDays || 35);
const TTL_MS   = ttlDays * 24 * 3600 * 1000;
const nowMs    = Date.now();

const entries0 = Array.isArray(seenStateIn.entries) ? seenStateIn.entries : [];
const pruned   = entries0.filter(r => {
  const ts = new Date(r.firstSeenAt || 0).getTime();
  return ts && (nowMs - ts) <= TTL_MS;
});

// 已存在则不重复追加
const existed = pruned.some(r => r.urlKey === urlKey || r.titleKey === titleKey);
if (!existed) {
  pruned.push({
    urlKey,
    titleKey,
    titleNorm,
    url: pickedMeta.url || '',
    source: pickedMeta.source || '',
    firstSeenAt: nowISO,
    algo: 'fnv1a32'
  });
}

// 序列化为 base64
const contentStr = JSON.stringify(pruned, null, 2);
const contentB64 = Buffer.from(contentStr, 'utf8').toString('base64');

// 读 GetSeen 拿 sha（200 有，404 就是 undefined）
const gsItem  = $items('GetSeen', 0, 0) || { json: {} };
const gsJson  = gsItem[0]?.json || {};
// 如果 HTTP 节点开启了 “Include response headers and status”，真正数据在 body 里
const payload = (gsJson && typeof gsJson.body === 'object') ? gsJson.body : gsJson;
// 只有 200（文件存在）时才会有 sha；首次创建（404）sha 为 null
const sha     = payload ? payload.sha : null;

const githubPutBody = {
  message: `chore(seen): +1 ${pickedRole} at ${nowISO}`,
  content: contentB64
};

if (sha) githubPutBody.sha = sha;    // 只有真的有 sha 才加

// ---------- 输出：只 1 条 item ----------
return [{
  json: {
    selected,
    githubPutBody,
    debug: { branchDebug, hadSeen: entries0.length, wroteSha: !!sha, sha:sha}
  }
}];

